-- Apply manual matches for the 11 review cases
-- Nodo West Village, CBD, Carindale → Nodo Pty Ltd (parent, no individual records exist)
UPDATE tiab_customers SET internalCustomerExternalId = 'C0171', matchConfidence = 0.75, matchType = 'manual_parent'
WHERE tiabCustomerId IN ('531874', '528323', '531871');

-- TYS Factory Unit → The Yiros Shop Factory Unit 4 (C0257)
UPDATE tiab_customers SET internalCustomerExternalId = 'C0257', matchConfidence = 0.80, matchType = 'manual_site'
WHERE tiabCustomerId = '534220';

-- TYS Valley Metro → The Yiros Shop Valley Metro (C0266)
UPDATE tiab_customers SET internalCustomerExternalId = 'C0266', matchConfidence = 0.85, matchType = 'fuzzy_high'
WHERE tiabCustomerId = '531118';

-- DJ Steel Monto → DJ Steel - Lyndarr Constructions Pty Ltd (C0077)
UPDATE tiab_customers SET internalCustomerExternalId = 'C0077', matchConfidence = 0.80, matchType = 'manual_site'
WHERE tiabCustomerId = '527025';

-- Sparrow Group → Sparrow Group Management Pty Ltd (C0222 - the full legal entity)
UPDATE tiab_customers SET internalCustomerExternalId = 'C0222', matchConfidence = 0.85, matchType = 'fuzzy_high'
WHERE tiabCustomerId = '532648';

-- CF Aust → CF Aust Pty Ltd (C0058) - exact match
UPDATE tiab_customers SET internalCustomerExternalId = 'C0058', matchConfidence = 0.90, matchType = 'fuzzy_high'
WHERE tiabCustomerId = '526985';

-- KHM Group Investments → KHM Group Investments (C0133)
UPDATE tiab_customers SET internalCustomerExternalId = 'C0133', matchConfidence = 0.88, matchType = 'fuzzy_high'
WHERE tiabCustomerId = '531876';

-- SmileTel Test → mark as internal/test (no customer match)
UPDATE tiab_customers SET internalCustomerExternalId = NULL, matchConfidence = 0.00, matchType = 'internal_test'
WHERE tiabCustomerId = '526902';

-- Orphan Services → mark as internal (SmileTel orphan pool)
UPDATE tiab_customers SET internalCustomerExternalId = NULL, matchConfidence = 0.00, matchType = 'internal_orphan'
WHERE tiabCustomerId = '525207';

SELECT tiabCustomerId, companyName, firstName, lastName, internalCustomerExternalId, matchType, matchConfidence
FROM tiab_customers
ORDER BY matchType, companyName;

